'use client'

import { useEffect, useRef } from 'react'

type RankRow = [score: number, count: number, cumulative: number, rankStart: number, rankEnd: number]
type RankData = { total: number; rows: RankRow[] }

const LOGO_SRC = 'data:image/jpeg;base64,'
const SEGMENTS = [[800, 700], [699, 600], [599, 500], [499, 400], [399, 300]] as const

export default function RankQueryPage() {
  const rootRef = useRef<HTMLDivElement>(null)
  const canvasRef = useRef<HTMLCanvasElement>(null)

  useEffect(() => {
    const root = rootRef.current
    const cv = canvasRef.current!
    if (!root) return

    const scoreInput = root.querySelector<HTMLInputElement>('#scoreIn')!
    const rankRange = root.querySelector<HTMLElement>('#rankRange')!
    const sameCount = root.querySelector<HTMLElement>('#sameCount')!
    const beatEl = root.querySelector<HTMLElement>('#beat')!
    const cumEl = root.querySelector<HTMLElement>('#cum')!
    const totalEl = root.querySelector<HTMLElement>('#totalN')!
    const tabsEl = root.querySelector<HTMLElement>('#segTabs')!
    const tbodyEl = root.querySelector<HTMLTableSectionElement>('#tbody')!
    const ctx = cv.getContext('2d')!

    let disposed = false
    let rows: RankRow[] = []
    let total = 0
    let byScore: Record<number, RankRow> = {}
    let minS = 300
    let maxS = 780
    let maxCount = 1
    let curScore = 678
    let curSeg = 0
    let dragging = false
    let startX = 0
    let startY = 0
    let isHorizontal = false
    let W = 0
    let H = 0
    let dpr = 1
    const PAD = { l: 8, r: 8, t: 14, b: 24 }

    function fmt(n: number | null) { return n == null ? '—' : n.toLocaleString() }
    function xFor(score: number) { return PAD.l + (score - minS) / (maxS - minS) * (W - PAD.l - PAD.r) }
    function yFor(count: number) { return H - PAD.b - (count / maxCount) * (H - PAD.t - PAD.b) }
    function scoreFromX(px: number) {
      let t = (px - PAD.l) / (W - PAD.l - PAD.r)
      t = Math.max(0, Math.min(1, t))
      return Math.round(minS + t * (maxS - minS))
    }
    function roundRect(c: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, r: number) {
      c.beginPath(); c.moveTo(x + r, y); c.arcTo(x + w, y, x + w, y + h, r)
      c.arcTo(x + w, y + h, x, y + h, r); c.arcTo(x, y + h, x, y, r); c.arcTo(x, y, x + w, y, r); c.closePath()
    }
    function draw() {
      ctx.clearRect(0, 0, W, H)
      if (!rows.length || !W || !H) return
      ctx.strokeStyle = '#F0EAE3'; ctx.lineWidth = 1
      ;[600, 700].forEach(g => { if (g >= minS && g <= maxS) { const x = xFor(g)
        ctx.beginPath(); ctx.setLineDash([4, 4]); ctx.moveTo(x, PAD.t); ctx.lineTo(x, H - PAD.b); ctx.stroke(); ctx.setLineDash([])
        ctx.fillStyle = '#A99'; ctx.font = '10px sans-serif'; ctx.textAlign = 'center'; ctx.fillText(String(g), x, H - 8) } })
      ctx.beginPath()
      const sorted = rows.slice().sort((a, b) => a[0] - b[0])
      sorted.forEach((r, i) => { const x = xFor(r[0]); const y = yFor(r[1]); i ? ctx.lineTo(x, y) : ctx.moveTo(x, y) })
      ctx.lineTo(xFor(maxS), H - PAD.b); ctx.lineTo(xFor(minS), H - PAD.b); ctx.closePath()
      const grad = ctx.createLinearGradient(0, PAD.t, 0, H - PAD.b)
      grad.addColorStop(0, 'rgba(232,120,74,.22)'); grad.addColorStop(1, 'rgba(232,120,74,.02)')
      ctx.fillStyle = grad; ctx.fill()
      ctx.beginPath()
      sorted.forEach((r, i) => { const x = xFor(r[0]); const y = yFor(r[1]); i ? ctx.lineTo(x, y) : ctx.moveTo(x, y) })
      ctx.strokeStyle = '#E8784A'; ctx.lineWidth = 2; ctx.stroke()
      const isTopBand = curScore >= 780 && curScore <= 800
      const r = isTopBand ? byScore[780] : byScore[curScore]
      if (r) {
        const x = xFor(curScore); const y = yFor(r[1])
        ctx.strokeStyle = '#1D9E75'; ctx.lineWidth = 1.5; ctx.setLineDash([5, 4])
        ctx.beginPath(); ctx.moveTo(x, PAD.t); ctx.lineTo(x, H - PAD.b); ctx.stroke(); ctx.setLineDash([])
        ctx.fillStyle = '#1D9E75'; ctx.beginPath(); ctx.arc(x, y, 5, 0, 7); ctx.fill()
        ctx.fillStyle = '#fff'; ctx.beginPath(); ctx.arc(x, y, 2, 0, 7); ctx.fill()
        const label = isTopBand ? `780以上 ${r[2]}人` : `${curScore}分 ${r[1]}人`
        ctx.font = 'bold 11px sans-serif'; const tw = ctx.measureText(label).width + 14
        let tx = x - tw / 2; tx = Math.max(2, Math.min(W - tw - 2, tx))
        ctx.fillStyle = '#1f2733'; roundRect(ctx, tx, PAD.t - 2, tw, 20, 5); ctx.fill()
        ctx.fillStyle = '#fff'; ctx.textAlign = 'center'; ctx.fillText(label, tx + tw / 2, PAD.t + 12)
      }
    }
    function resize() {
      dpr = window.devicePixelRatio || 1
      W = cv.clientWidth; H = cv.clientHeight
      cv.width = W * dpr; cv.height = H * dpr
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0)
      draw()
    }
    function buildTabs() {
      tabsEl.innerHTML = ''
      SEGMENTS.forEach((sg, i) => {
        const b = document.createElement('button')
        b.textContent = `${sg[0]}-${sg[1]}分`; if (i === curSeg) b.className = 'on'
        b.onclick = () => { curSeg = i; buildTabs(); buildTable() }
        tabsEl.appendChild(b)
      })
    }
    function buildTable() {
      const [hi, lo] = SEGMENTS[curSeg]
      tbodyEl.innerHTML = ''
      rows.filter(r => r[0] <= hi && r[0] >= lo).sort((a, b) => b[0] - a[0]).forEach(r => {
        const tr = document.createElement('tr')
        if (r[0] === curScore || (r[0] === 780 && curScore >= 780 && curScore <= 800)) tr.className = 'cur'
        tr.innerHTML = `<td class="s">${r[0] === 780 ? '780以上' : r[0]}</td><td>${r[0] === 780 ? r[2] : r[1]}</td><td>${r[2].toLocaleString()}</td><td>${r[3].toLocaleString()}-${r[4].toLocaleString()}</td>`
        tr.onclick = () => { curScore = r[0]; scoreInput.value = String(r[0]); update() }
        tbodyEl.appendChild(tr)
      })
    }
    function highlightRow() {
      const idx = curScore >= 780 && curScore <= 800 ? 0 : SEGMENTS.findIndex(sg => curScore <= sg[0] && curScore >= sg[1])
      if (idx >= 0 && idx !== curSeg) { curSeg = idx; buildTabs() }
      buildTable()
    }
    function update() {
      const isTopBand = curScore >= 780 && curScore <= 800
      const r = isTopBand ? byScore[780] : byScore[curScore]
      if (!r) {
        rankRange.textContent = '超出范围'; sameCount.innerHTML = '—'; beatEl.innerHTML = '—'; cumEl.innerHTML = '—'
      } else {
        const [, rawCount, cum, rs, re] = r
        const cnt = isTopBand ? cum : rawCount
        rankRange.textContent = `${rs.toLocaleString()}~${re.toLocaleString()}`
        sameCount.innerHTML = `${fmt(cnt)}<small>人</small>`
        const beat = (total - cum) / total * 100
        beatEl.innerHTML = `${beat.toFixed(1)}<small>%</small>`
        cumEl.innerHTML = `${fmt(cum)}<small>人</small>`
      }
      draw(); highlightRow()
    }
    function pickFromEvent(e: MouseEvent | TouchEvent) {
      const rect = cv.getBoundingClientRect()
      const clientX = 'touches' in e ? (e.touches[0] || e.changedTouches[0])?.clientX : e.clientX
      if (clientX == null) return
      const s = scoreFromX(clientX - rect.left)
      if (s >= minS && s <= maxS) { curScore = s; scoreInput.value = String(s); update() }
    }

    const onMouseDown = (e: MouseEvent) => { dragging = true; pickFromEvent(e) }
    const onMouseMove = (e: MouseEvent) => { if (dragging) pickFromEvent(e) }
    const onMouseUp = () => { dragging = false }
    const onTouchStart = (e: TouchEvent) => {
      const touch = e.touches[0]
      if (!touch) return
      startX = touch.clientX
      startY = touch.clientY
      isHorizontal = false
      dragging = false
    }
    const onTouchMove = (e: TouchEvent) => {
      const touch = e.touches[0]
      if (!touch) return
      const dx = Math.abs(touch.clientX - startX)
      const dy = Math.abs(touch.clientY - startY)
      if (!isHorizontal && !dragging) {
        if (dy > dx && dy > 6) return
        if (dx > dy && dx > 6) {
          isHorizontal = true
          dragging = true
        }
      }
      if (isHorizontal) {
        e.preventDefault()
        pickFromEvent(e)
      }
    }
    const onTouchEnd = (e: TouchEvent) => {
      const touch = e.changedTouches[0]
      const dx = touch ? Math.abs(touch.clientX - startX) : 0
      const dy = touch ? Math.abs(touch.clientY - startY) : 0
      if (!isHorizontal && Math.max(dx, dy) <= 6) pickFromEvent(e)
      dragging = false
      isHorizontal = false
    }
    const onTouchCancel = () => {
      dragging = false
      isHorizontal = false
    }
    const onInput = (e: Event) => { const v = parseInt((e.target as HTMLInputElement).value); if (!Number.isNaN(v)) { curScore = v; update() } }
    const quickButtons = Array.from(root.querySelectorAll<HTMLButtonElement>('.quick button'))
    const quickHandlers = quickButtons.map(button => {
      const handler = () => { curScore = parseInt(button.dataset.s || '678'); scoreInput.value = String(curScore); update() }
      button.addEventListener('click', handler)
      return { button, handler }
    })

    cv.addEventListener('mousedown', onMouseDown)
    window.addEventListener('mousemove', onMouseMove)
    window.addEventListener('mouseup', onMouseUp)
    cv.addEventListener('touchstart', onTouchStart, { passive: false })
    cv.addEventListener('touchmove', onTouchMove, { passive: false })
    cv.addEventListener('touchend', onTouchEnd)
    cv.addEventListener('touchcancel', onTouchCancel)
    scoreInput.addEventListener('input', onInput)
    window.addEventListener('resize', resize)

    fetch('/api/volunteer/yifenyidang?year=2025')
      .then(async response => {
        const payload = await response.json()
        if (!response.ok) throw new Error(payload.error || '数据加载失败')
        return payload as RankData
      })
      .then(data => {
        if (disposed || !Array.isArray(data.rows) || data.rows.length === 0) throw new Error('暂无数据')
        rows = data.rows; total = data.total
        byScore = {}; rows.forEach(r => { byScore[r[0]] = r })
        const scoresAsc = rows.map(r => r[0]).sort((a, b) => a - b)
        minS = scoresAsc[0]; maxS = Math.max(800, scoresAsc[scoresAsc.length - 1])
        maxCount = Math.max(...rows.map(r => r[1]))
        totalEl.textContent = total.toLocaleString()
        buildTabs(); resize(); update()
      })
      .catch(error => {
        if (disposed) return
        console.error('一分一档数据加载失败', error)
        totalEl.textContent = '暂无数据'
        rankRange.textContent = '暂无数据'
      })

    return () => {
      disposed = true
      cv.removeEventListener('mousedown', onMouseDown)
      window.removeEventListener('mousemove', onMouseMove)
      window.removeEventListener('mouseup', onMouseUp)
      cv.removeEventListener('touchstart', onTouchStart)
      cv.removeEventListener('touchmove', onTouchMove)
      cv.removeEventListener('touchend', onTouchEnd)
      cv.removeEventListener('touchcancel', onTouchCancel)
      scoreInput.removeEventListener('input', onInput)
      window.removeEventListener('resize', resize)
      quickHandlers.forEach(({ button, handler }) => button.removeEventListener('click', handler))
    }
  }, [])

  return (
    <div className="rank-query-page" ref={rootRef}>
      <div className="wrap">
        <div className="top">
          <img src={LOGO_SRC} alt="牧哲学堂" />
          <div className="titles">
            <h1>石家庄中考一分一档 · 位次查询</h1>
            <p>2025年石家庄17县市区中考成绩位次对照 · 牧哲学堂 MOREJOY</p>
          </div>
          <span className="badge">2025年数据</span>
        </div>

        <div className="panel">
          <div className="ctrl-row">
            <span className="ctrl-label">分数</span>
            <div className="score-input">
              <input id="scoreIn" type="number" min="300" max="800" defaultValue="678" inputMode="numeric" />
              <span className="unit">分 / 满分800</span>
            </div>
          </div>
          <div className="quick">
            <button data-s="800">800</button><button data-s="750">750</button><button data-s="700">700</button>
            <button data-s="678">678</button><button data-s="650">650</button>
            <button data-s="624">624</button><button data-s="600">600</button>
            <button data-s="550">550</button><button data-s="500">500</button>
          </div>

          <div className="stats">
            <div className="stat hl"><div className="k">全市位次区间</div><div className="v" id="rankRange">—</div></div>
            <div className="stat"><div className="k">同分人数</div><div className="v" id="sameCount">—<small>人</small></div></div>
            <div className="stat hl2"><div className="k">超过考生</div><div className="v" id="beat">—<small>%</small></div></div>
            <div className="stat"><div className="k">累计人数</div><div className="v" id="cum">—<small>人</small></div></div>
          </div>

          <div className="chart-card">
            <div className="chart-head">
              <h3>一分一档分布曲线</h3>
              <span className="hint">拖动曲线或点击查看任意分数</span>
            </div>
            <canvas id="chart" ref={canvasRef}></canvas>
            <div className="axis-note">横轴 = 分数(300→800) · 纵轴 = 该分人数 · 竖线为当前查询分数</div>
          </div>
        </div>

        <div className="panel band">
          <h3>全部分数段明细</h3>
          <div className="seg-tabs" id="segTabs"></div>
          <div style={{ maxHeight: 360, overflow: 'auto' }}>
            <table>
              <thead><tr><th>分数</th><th>人数</th><th>累计人数</th><th>位次区间</th></tr></thead>
              <tbody id="tbody"></tbody>
            </table>
          </div>
        </div>

        <div className="foot">
          数据来源：2025年石家庄市中考一分一档（17县市区）· 共 <span id="totalN">数据加载中</span> 人<br />
          本工具仅供位次参考，最终以石家庄市教育考试院官方公布为准 · 牧哲学堂 MOREJOY
        </div>
      </div>

      <style jsx global>{`
        *{box-sizing:border-box;margin:0;padding:0}
        :root{
          --coral:#E8784A; --coral-soft:#FBEDE5; --teal:#1D9E75; --teal-soft:#E5F4EF;
          --ink:#1f2733; --ink-soft:#5b6675; --line:#ECE7E1; --bg:#FAF7F3; --card:#fff;
        }
        body{font-family:"PingFang SC","Microsoft YaHei",-apple-system,sans-serif;
          background:var(--bg);color:var(--ink);line-height:1.55;-webkit-font-smoothing:antialiased}
        .wrap{max-width:1000px;margin:0 auto;padding:20px 16px 60px}
        /* header */
        .top{display:flex;align-items:center;gap:14px;padding:6px 2px 18px;flex-wrap:wrap}
        .top img{height:46px}
        .top .titles{display:flex;flex-direction:column}
        .top h1{font-size:19px;font-weight:800;letter-spacing:.5px}
        .top p{font-size:12.5px;color:var(--ink-soft)}
        .top .badge{margin-left:auto;background:var(--coral-soft);color:var(--coral);
          font-size:12px;font-weight:700;padding:5px 12px;border-radius:20px}
        /* controls */
        .panel{background:var(--card);border:1px solid var(--line);border-radius:16px;
          padding:22px 24px;box-shadow:0 1px 3px rgba(80,60,40,.04)}
        .ctrl-row{display:flex;align-items:center;gap:14px;flex-wrap:wrap}
        .ctrl-label{font-size:13px;color:var(--ink-soft);font-weight:600;min-width:42px}
        .score-input{display:flex;align-items:baseline;gap:10px}
        .score-input input{width:150px;font-size:40px;font-weight:800;color:var(--coral);
          border:none;border-bottom:2.5px solid var(--coral);background:transparent;
          text-align:center;font-family:inherit;outline:none;padding:2px 0}
        .score-input input::-webkit-outer-spin-button,.score-input input::-webkit-inner-spin-button{-webkit-appearance:none}
        .score-input .unit{font-size:14px;color:var(--ink-soft)}
        .quick{display:flex;gap:8px;flex-wrap:wrap;margin-top:4px}
        .quick button{font-size:12.5px;padding:5px 12px;border:1px solid var(--line);
          background:#fff;border-radius:20px;cursor:pointer;color:var(--ink-soft);transition:.15s}
        .quick button:hover{border-color:var(--coral);color:var(--coral)}
        /* result stat */
        .stats{display:grid;grid-template-columns:repeat(4,1fr);gap:1px;background:var(--line);
          border-radius:14px;overflow:hidden;margin-top:20px;border:1px solid var(--line)}
        .stat{background:var(--card);padding:16px 18px}
        .stat .k{font-size:12px;color:var(--ink-soft);margin-bottom:6px}
        .stat .v{font-size:23px;font-weight:800;color:var(--ink)}
        .stat .v small{font-size:13px;font-weight:600;color:var(--ink-soft);margin-left:2px}
        .stat.hl .v{color:var(--coral)}
        .stat.hl2 .v{color:var(--teal)}
        /* chart */
        .chart-card{margin-top:18px}
        .chart-head{display:flex;justify-content:space-between;align-items:center;margin-bottom:6px}
        .chart-head h3{font-size:14px;font-weight:700}
        .chart-head .hint{font-size:11.5px;color:var(--ink-soft)}
        #chart{width:100%;height:300px;display:block;touch-action:pan-y;cursor:crosshair}
        .axis-note{font-size:11px;color:var(--ink-soft);text-align:center;margin-top:4px}
        /* band table */
        .band{margin-top:18px}
        .band h3{font-size:14px;font-weight:700;margin-bottom:10px}
        .seg-tabs{display:flex;gap:8px;flex-wrap:wrap;margin-bottom:12px}
        .seg-tabs button{font-size:12.5px;padding:6px 14px;border:1px solid var(--line);
          background:#fff;border-radius:8px;cursor:pointer;color:var(--ink-soft)}
        .seg-tabs button.on{background:var(--coral);color:#fff;border-color:var(--coral)}
        table{width:100%;border-collapse:collapse;font-size:13px}
        thead th{text-align:left;color:var(--ink-soft);font-weight:600;font-size:12px;
          padding:8px 12px;border-bottom:1.5px solid var(--line)}
        tbody td{padding:9px 12px;border-bottom:1px solid var(--line)}
        tbody tr:hover{background:var(--coral-soft)}
        tbody tr.cur{background:var(--teal-soft)}
        tbody td.s{font-weight:700;color:var(--coral)}
        .foot{font-size:11px;color:var(--ink-soft);margin-top:24px;text-align:center;line-height:1.7}
        @media(max-width:680px){
          .rank-query-page{width:100%;max-width:100%;overflow-x:hidden}
          .wrap{width:100%;max-width:100%;padding:12px 0 92px}
          .top{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:8px 10px;padding:2px 2px 14px}
          .top img{width:min(220px,100%);height:auto;max-height:46px;object-fit:contain;object-position:left center}
          .top .titles{grid-column:1/-1;min-width:0}
          .top h1{font-size:18px;line-height:1.35;letter-spacing:0}
          .top p{font-size:12px;line-height:1.55}
          .top .badge{align-self:center;justify-self:end;margin-left:0;order:initial;padding:4px 10px}
          .panel{width:100%;max-width:100%;padding:16px 12px;border-radius:12px}
          .ctrl-row{display:grid;grid-template-columns:38px minmax(0,1fr);gap:10px}
          .ctrl-label{min-width:0}
          .score-input{min-width:0;gap:8px}
          .score-input input{width:108px;max-width:42%;font-size:32px}
          .score-input .unit{font-size:12px;white-space:nowrap}
          .quick{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:8px;margin-top:10px}
          .quick button{width:100%;min-width:0;padding:6px 4px}
          .stats{grid-template-columns:repeat(2,1fr)}
          .stat{min-width:0;padding:12px 10px;overflow:hidden}
          .stat .k{font-size:11px;margin-bottom:5px;white-space:nowrap}
          .stat .v{font-size:18px;line-height:1.3;letter-spacing:0;white-space:nowrap;font-variant-numeric:tabular-nums}
          .stat .v small{font-size:11px}
          #rankRange{font-size:17px}
          .chart-card{margin-top:16px}
          .chart-head{align-items:flex-start;gap:8px}
          .chart-head .hint{max-width:48%;text-align:right;line-height:1.4}
          #chart{height:230px}
          .axis-note{font-size:10px;line-height:1.5}
          .band{margin-top:12px;padding:16px 10px}
          .seg-tabs{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:8px}
          .seg-tabs button{width:100%;min-width:0;padding:7px 4px;font-size:12px}
          table{table-layout:fixed;font-size:11.5px}
          thead th,tbody td{padding:8px 4px;letter-spacing:0}
          thead th{font-size:11px;line-height:1.35}
          thead th:nth-child(1),tbody td:nth-child(1){width:17%}
          thead th:nth-child(2),tbody td:nth-child(2){width:16%}
          thead th:nth-child(3),tbody td:nth-child(3){width:27%}
          thead th:nth-child(4),tbody td:nth-child(4){width:40%;white-space:nowrap}
          .foot{padding:0 8px;margin-top:18px;font-size:10.5px}
        }
      `}</style>
    </div>
  )
}
